"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[597],{2861:e=>{e.exports=JSON.parse('{"functions":[{"name":"RegisterDefinition","desc":"Registers a movement module with input actions, default state fields, and a\\n`Process` function.\\n\\nModules run in priority order (lower runs first). Register before `Start`\\nwhen possible; if already started, active players are updated immediately.\\nDuplicate names are ignored.","params":[{"name":"self","desc":"","lua_type":"ServerAuthToolkit"},{"name":"definition","desc":"Module definition to register","lua_type":"ServerAuthToolkitTypes.MovementModuleDefinition"}],"returns":[],"function_type":"static","tags":["Register"],"source":{"line":852,"path":"src/init.luau"}},{"name":"Teleport","desc":"Teleports a player\'s character to a target CFrame with server authority.\\n\\nServer-only. Sets the root part CFrame and replicates the new state so\\npredicting clients roll back to it.\\n\\nThe toolkit does not assume any module-specific state fields. Pass\\n`modifyState` to mutate the player\'s authoritative movement state before it is\\ncaptured to attributes (for example, zeroing a module\'s `Velocity` so the\\ncharacter does not keep its momentum after the move). The callback runs after\\nthe position is resolved and before replication.","params":[{"name":"self","desc":"","lua_type":"ServerAuthToolkit"},{"name":"player","desc":"The player whose character to teleport","lua_type":"Player"},{"name":"targetCFrame","desc":"Destination CFrame; position is used, facing is flattened","lua_type":"CFrame"},{"name":"modifyState","desc":"Optional hook to mutate the movement state before replication","lua_type":"((state: MovementState) -> ())?"},{"name":"preserveLookDirection","desc":"When true, keeps the current facing instead of using targetCFrame","lua_type":"boolean?"}],"returns":[{"desc":"True if the teleport was applied","lua_type":"boolean"}],"function_type":"static","tags":["Utility"],"realm":["Server"],"source":{"line":899,"path":"src/init.luau"}},{"name":"RegisterPreCameraSimulation","desc":"Registers a callback that runs on the client before movement simulation each\\nframe.\\n\\nUse for client-only setup that must happen before input is applied. Callbacks\\nrun in registration order. Server calls log a warning and return a no-op\\nunregister function.","params":[{"name":"self","desc":"","lua_type":"ServerAuthToolkit"},{"name":"callbackName","desc":"Unique name for this callback","lua_type":"string"},{"name":"callback","desc":"Called each pre-simulation step with deltaTime","lua_type":"ServerAuthToolkitTypes.PreCameraSimulationCallback"}],"returns":[{"desc":"Unregisters the callback","lua_type":"() -> ()"}],"function_type":"static","tags":["Camera"],"realm":["Client"],"source":{"line":968,"path":"src/init.luau"}},{"name":"RegisterPostCameraVisualEffect","desc":"Registers a visual callback that runs on the client after the camera updates.\\n\\nUse for camera shake, FOV changes, or other effects that should not affect\\nmovement simulation. Server calls log a warning and return a no-op unregister\\nfunction.","params":[{"name":"self","desc":"","lua_type":"ServerAuthToolkit"},{"name":"callbackName","desc":"Unique name for this callback","lua_type":"string"},{"name":"callback","desc":"Called each render step with deltaTime","lua_type":"ServerAuthToolkitTypes.PostCameraVisualCallback"},{"name":"renderPriorityOffset","desc":"Offset from camera render priority. Defaults to 2","lua_type":"number?"}],"returns":[{"desc":"Unregisters the callback","lua_type":"() -> ()"}],"function_type":"static","tags":["Camera"],"realm":["Client"],"source":{"line":1010,"path":"src/init.luau"}},{"name":"GetStoredSimulationCameraBaseCFrame","desc":"Returns the camera CFrame captured for client movement simulation.\\n\\nThe toolkit stores this after the camera updates so simulation uses a stable\\ncamera state. Returns nil on the server or before a capture exists.","params":[{"name":"self","desc":"","lua_type":"ServerAuthToolkit"}],"returns":[{"desc":"The stored simulation camera CFrame","lua_type":"CFrame?"}],"function_type":"static","tags":["Camera"],"realm":["Client"],"source":{"line":1052,"path":"src/init.luau"}},{"name":"ResetNeededStates","desc":"Resets a player\'s custom movement state fields to the merged defaults from\\nall registered modules.\\n\\nOnly fields from module `NeededStates` are reset. Built-in fields like\\n`Character` and `RootPart` are not changed.","params":[{"name":"self","desc":"","lua_type":"ServerAuthToolkit"},{"name":"playerMovementState","desc":"The movement state to reset","lua_type":"ServerAuthToolkitTypes.MovementState"}],"returns":[],"function_type":"static","tags":["States"],"source":{"line":1070,"path":"src/init.luau"}},{"name":"GetLocalMovementState","desc":"Returns the local player\'s movement state table.\\n\\nThis is the same table updated each simulation step by registered modules.\\nReturns nil on the server.","params":[{"name":"self","desc":"","lua_type":"ServerAuthToolkit"}],"returns":[{"desc":"The local player\'s movement state","lua_type":"ServerAuthToolkitTypes.MovementState?"}],"function_type":"static","tags":["States"],"realm":["Client"],"source":{"line":1087,"path":"src/init.luau"}},{"name":"RegisterAnimations","desc":"Registers animations for use with the animation API.\\n\\nEach name maps to playback settings used by `PlayAnimation`, `StopAnimation`,\\nand the animation query methods.","params":[{"name":"self","desc":"","lua_type":"ServerAuthToolkit"},{"name":"animations","desc":"Animation names to settings","lua_type":"{ [string]: ServerAuthToolkitTypes.AnimationSettings }"}],"returns":[],"function_type":"static","tags":["Register"],"source":{"line":1104,"path":"src/init.luau"}},{"name":"PlayAnimation","desc":"Plays a registered animation.\\n\\nThe animation must be registered first with `RegisterAnimations`.","params":[{"name":"self","desc":"","lua_type":"ServerAuthToolkit"},{"name":"animationName","desc":"The animation to play","lua_type":"string"},{"name":"speedOverride","desc":"Optional playback speed. Uses registered speed if omitted","lua_type":"number?"}],"returns":[],"function_type":"static","tags":["Animations"],"source":{"line":1122,"path":"src/init.luau"}},{"name":"StopAnimation","desc":"Stops a registered animation.\\n\\nUses the registered stop fade time when blending out.","params":[{"name":"self","desc":"","lua_type":"ServerAuthToolkit"},{"name":"animationName","desc":"The animation to stop","lua_type":"string"}],"returns":[],"function_type":"static","tags":["Animations"],"source":{"line":1134,"path":"src/init.luau"}},{"name":"IsAnimationPlaying","desc":"Returns whether a registered animation is currently playing.","params":[{"name":"self","desc":"","lua_type":"ServerAuthToolkit"},{"name":"animationName","desc":"The animation to check","lua_type":"string"}],"returns":[{"desc":"True if the animation is playing","lua_type":"boolean"}],"function_type":"static","tags":["Animations"],"source":{"line":1145,"path":"src/init.luau"}},{"name":"IsAnimationFinished","desc":"Returns whether a non-looped animation has finished playing.\\n\\nLooped animations always return false.","params":[{"name":"self","desc":"","lua_type":"ServerAuthToolkit"},{"name":"animationName","desc":"The animation to check","lua_type":"string"}],"returns":[{"desc":"True if the animation has finished","lua_type":"boolean"}],"function_type":"static","tags":["Animations"],"source":{"line":1158,"path":"src/init.luau"}},{"name":"WriteFlatLookDirection","desc":"Stores a flat look direction on a root part for replication.\\n\\nThe toolkit reads this at the end of each simulation step to orient the\\ncharacter. The Y component should usually be zero.","params":[{"name":"self","desc":"","lua_type":"ServerAuthToolkit"},{"name":"rootPart","desc":"The character root part","lua_type":"BasePart"},{"name":"flatLookDirection","desc":"The horizontal look direction in world space","lua_type":"Vector3"}],"returns":[],"function_type":"static","tags":["Utility"],"source":{"line":1172,"path":"src/init.luau"}},{"name":"ReadFlatLookDirection","desc":"Reads the flat look direction stored on a root part.\\n\\nReturns `Vector3.new(0, 0, -1)` if no direction has been stored.","params":[{"name":"self","desc":"","lua_type":"ServerAuthToolkit"},{"name":"rootPart","desc":"The character root part","lua_type":"BasePart"}],"returns":[{"desc":"The stored flat look direction","lua_type":"Vector3"}],"function_type":"static","tags":["Utility"],"source":{"line":1189,"path":"src/init.luau"}},{"name":"QuantizeFlatDirection","desc":"Rounds a flat direction to a fixed yaw step for stable network replication.\\n\\nYaw is quantized to 0.25 degree steps. Useful before calling\\n`WriteFlatLookDirection`.","params":[{"name":"self","desc":"","lua_type":"ServerAuthToolkit"},{"name":"flatDirection","desc":"The direction to quantize","lua_type":"Vector3"}],"returns":[{"desc":"The quantized direction on the horizontal plane","lua_type":"Vector3"}],"function_type":"static","tags":["Utility"],"source":{"line":1203,"path":"src/init.luau"}},{"name":"Start","desc":"Starts movement simulation, player lifecycle handling, and the animation helper.\\n\\nCall once on the server and once on the client after registering modules.\\nSafe to call multiple times; later calls do nothing.","params":[{"name":"self","desc":"","lua_type":"ServerAuthToolkit"}],"returns":[],"function_type":"static","tags":["Register"],"source":{"line":1215,"path":"src/init.luau"}}],"properties":[],"types":[{"name":"MovementState","desc":"Per-player movement state updated each simulation step. Built-in fields track\\nthe character and ground info; modules add custom fields through `NeededStates`.","lua_type":"{ Character: Model?, Humanoid: Humanoid?, RootPart: BasePart?, CameraLookVector: Vector3?, OnGround: boolean?, GroundNormal: Vector3?, [string]: any }","tags":["General"],"source":{"line":15,"path":"src/ServerAuthToolkitTypes.luau"}},{"name":"BindingProps","desc":"Optional input binding settings for an action. Keys map to Roblox\\nInputBinding properties such as key codes, modifiers, and scale values.","lua_type":"{ Backward: Enum.KeyCode?, ClampMagnitudeToOne: boolean?, Down: Enum.KeyCode?, Forward: Enum.KeyCode?, KeyCode: Enum.KeyCode?, Left: Enum.KeyCode?, PointerIndex: number?, PressedThreshold: number?, PrimaryModifier: Enum.KeyCode?, ReleasedThreshold: number?, ResponseCurve: number?, Right: Enum.KeyCode?, Scale: number?, SecondaryModifier: Enum.KeyCode?, UIButton: Enum.UserInputType?, Up: Enum.KeyCode?, Vector2Scale: Vector2?, Vector3Scale: Vector3? }","tags":["Input Action System"],"source":{"line":41,"path":"src/ServerAuthToolkitTypes.luau"}},{"name":"ActionDefinition","desc":"Describes one input action in a movement module. `ApplyInput` writes the\\naction state into the player\'s movement state each simulation step.","lua_type":"{ Name: string, Type: Enum.InputActionType, Bindings: { [string]: BindingProps }, ApplyInput: (state: MovementState, inputState: any) -> () }","tags":["Input Action System"],"source":{"line":70,"path":"src/ServerAuthToolkitTypes.luau"}},{"name":"MovementModuleDefinition","desc":"Describes a movement module: input actions, default state, per-frame logic, and\\noptional Roblox actions to disable. Lower `Priority` runs first.","lua_type":"{ Name: string, Priority: number?, Actions: { ActionDefinition }, NeededStates: NeededStatesDefaults, Process: (state: MovementState, deltaTime: number) -> (), Disable: { string }? }","tags":["General"],"source":{"line":85,"path":"src/ServerAuthToolkitTypes.luau"}},{"name":"PreCameraSimulationEntry","desc":"Internal entry for a registered pre-camera simulation callback.","lua_type":"{ name: string, callback: PreCameraSimulationCallback }","tags":["Callbacks"],"source":{"line":110,"path":"src/ServerAuthToolkitTypes.luau"}},{"name":"PostCameraVisualEntry","desc":"Internal entry for a registered post-camera visual callback.","lua_type":"{ name: string, callback: PostCameraVisualCallback, priority: number }","tags":["Callbacks"],"source":{"line":122,"path":"src/ServerAuthToolkitTypes.luau"}},{"name":"AnimationSettings","desc":"Playback settings for a registered animation.","lua_type":"{ Speed: number, Weight: number, FadeTime: number, StopFadeTime: number, Looped: boolean, Priority: Enum.AnimationPriority, Animation: Animation }","tags":["General"],"source":{"line":135,"path":"src/ServerAuthToolkitTypes.luau"}}],"name":"ServerAuthToolkit","desc":"Server-authoritative movement toolkit for Roblox Input Actions and client\\nprediction.\\n\\nRegister movement modules and animations, then call `Start` on both the server\\nand client. Modules run each simulation step in priority order and replicate\\nstate through root-part attributes.","source":{"line":11,"path":"src/init.luau"}}')}}]);